const mergeSeedRecords=(seedRows,cachedRows)=>{
  if(!Array.isArray(cachedRows)||!cachedRows.length)return seedRows
  const defaults=new Map(seedRows.map(item=>[item.id,item]))
  return cachedRows.map(item=>({...defaults.get(item.id),...item}))
}

