function currentRoute(){return (window.location.hash.replace(/^#\/?/,'').split('?')[0]||'dashboard').replace(/\/$/,'')}
function go(route){window.location.hash=`/${route}`}
function makeId(prefix){return `${prefix}-${String(Date.now()).slice(-6)}`}
function saveFile(name,content,type='text/csv'){const blob=new Blob([content],{type});const url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;a.download=name;a.click();URL.revokeObjectURL(url)}

function Logo({light=false,compact=false}){return <a href={LANDING_URL} className="flex items-center gap-3" aria-label="Alliance Air Cargo home"><span className="grid h-10 w-10 shrink-0 place-items-center rounded-xl bg-brand text-white shadow-lg shadow-blue-950/15"><svg viewBox="0 0 48 48" className="h-7 w-7"><path d="M8 30.5 24.7 12l15.6 3.6-14.8 6.6-5.4 12.9-3.8-8.9-8.3 4.3Z" fill="currentColor"/><path d="m18.8 24.9 7.1-2.9" stroke="#F4B400" strokeWidth="2.4" strokeLinecap="round"/></svg></span>{!compact&&<span className="leading-none"><strong className={`font-display block text-[15px] ${light?'text-white':'text-navy'}`}>ALLIANCE</strong><span className={`mt-1 block text-[8px] font-bold tracking-[.2em] ${light?'text-blue-200':'text-brand'}`}>SUPER ADMIN</span></span>}</a>}

function Toast({data,onClose}){if(!data)return null;return <div role="status" className={`fixed right-4 top-4 z-[120] flex max-w-sm items-start gap-3 rounded-xl border bg-white p-4 text-xs shadow-2xl ${data.type==='error'?'border-red-200':'border-green-200'}`}>{data.type==='error'?<XCircle className="shrink-0 text-red-500" size={19}/>:<CheckCircle2 className="shrink-0 text-green-600" size={19}/>}<span className="leading-5 text-slate-600">{data.message}</span><button onClick={onClose}><X size={15}/></button></div>}

function Confirm({open,title,text,onCancel,onConfirm}){if(!open)return null;return <div className="fixed inset-0 z-[110] grid place-items-center bg-navy/45 p-4 backdrop-blur-sm"><div className="fade w-full max-w-sm rounded-2xl bg-white p-6 shadow-2xl"><span className="grid h-11 w-11 place-items-center rounded-full bg-red-50 text-red-500"><AlertTriangle size={21}/></span><h2 className="font-display mt-4 text-lg font-semibold text-navy">{title}</h2><p className="mt-2 text-xs leading-5 text-slate-500">{text}</p><div className="mt-6 flex justify-end gap-2"><button className="btn-secondary" onClick={onCancel}>Cancel</button><button className="btn-primary bg-red-600 hover:bg-red-700" onClick={onConfirm}>Confirm</button></div></div></div>}

function Modal({open,title,children,onClose,wide=false}){if(!open)return null;return <div className="fixed inset-0 z-[100] overflow-y-auto bg-navy/45 p-3 backdrop-blur-sm sm:p-6"><div className={`fade mx-auto my-4 w-full rounded-2xl bg-white shadow-2xl ${wide?'max-w-3xl':'max-w-xl'}`}><div className="sticky top-0 z-10 flex items-center justify-between rounded-t-2xl border-b border-slate-100 bg-white px-6 py-5"><h2 className="font-display text-lg font-semibold text-navy">{title}</h2><button onClick={onClose} className="grid h-9 w-9 place-items-center rounded-lg bg-slate-100 text-slate-500"><X size={18}/></button></div><div className="p-6">{children}</div></div></div>}

function AdminLogin({onLogin,toast}){
  const [stage,setStage]=useState('password'),[email,setEmail]=useState(ADMIN_LOGIN.email),[password,setPassword]=useState(ADMIN_LOGIN.password),[otp,setOtp]=useState(''),[loading,setLoading]=useState(false)
  const submit=async e=>{e.preventDefault();if(stage==='password'){if(email!==ADMIN_LOGIN.email||password!==ADMIN_LOGIN.password)return toast('Invalid credentials. Use the demo access shown below.','error');setLoading(true);setTimeout(()=>{setLoading(false);setStage('otp');toast('Security code generated. Demo code: 246810')},500)}else{if(otp!=='246810')return toast('Incorrect code. Use 246810.','error');setLoading(true);try{await api.post('/api/auth/login',{email,password,otp,role:'superadmin'});onLogin()}catch(error){toast(error.message||'Unable to sign in right now.','error')}finally{setLoading(false)}}}
  return <main className="min-h-screen bg-white lg:grid lg:grid-cols-[1.08fr_.92fr]"><section className="auth-grid relative hidden min-h-screen overflow-hidden bg-navy p-14 text-white lg:flex lg:flex-col"><div className="absolute -bottom-40 -right-32 h-[560px] w-[560px] rounded-full border border-white/10"/><div className="absolute -bottom-24 -right-14 h-[390px] w-[390px] rounded-full border border-white/10"/><Logo light/><div className="relative my-auto max-w-xl"><span className="inline-flex items-center gap-2 rounded-full border border-white/15 bg-white/10 px-4 py-2 text-xs font-semibold text-blue-100"><ShieldCheck size={15} className="text-gold"/> Enterprise control centre</span><h1 className="font-display mt-7 text-5xl font-semibold leading-[1.1] tracking-[-.045em]">Control every cargo operation with clarity.</h1><p className="mt-5 max-w-lg text-[15px] leading-7 text-blue-100/70">Secure administration for bookings, flights, rates, stations, payments, teams and compliance—across the complete Alliance network.</p><div className="mt-10 flex flex-wrap gap-3">{['Role-based access','Complete audit trail','2-step verification'].map(x=><span key={x} className="rounded-lg bg-white/[.07] px-4 py-3 text-xs text-blue-100/80">{x}</span>)}</div></div><p className="text-[10px] text-blue-200/50">Restricted system · Authorized personnel only</p></section><section className="flex min-h-screen flex-col"><header className="flex h-20 items-center justify-between border-b border-slate-100 px-5 lg:hidden"><Logo/><a href={LANDING_URL} className="text-xs font-bold text-brand">Main site</a></header><div className="mx-auto flex w-full max-w-[490px] flex-1 flex-col justify-center px-5 py-10 sm:px-9"><a href={LANDING_URL} className="mb-8 hidden items-center gap-2 text-xs font-semibold text-slate-400 hover:text-brand lg:inline-flex"><ArrowLeft size={15}/> Back to public website</a><span className="mb-5 grid h-12 w-12 place-items-center rounded-xl bg-sky text-brand">{stage==='password'?<LockKeyhole size={23}/>:<Smartphone size={23}/>}</span><h2 className="font-display text-3xl font-semibold tracking-[-.035em] text-navy">{stage==='password'?'Super Admin sign in':'Verify your identity'}</h2><p className="mt-2 text-sm leading-6 text-slate-500">{stage==='password'?'Enter your authorized administrator credentials.':'Enter the 6-digit security code for this demo.'}</p><form onSubmit={submit} className="mt-7 space-y-4">{stage==='password'?<><label className="label">Admin email<input className="field mt-2" type="email" value={email} onChange={e=>setEmail(e.target.value)} required/></label><label className="label">Password<input className="field mt-2" type="password" value={password} onChange={e=>setPassword(e.target.value)} required/></label><div className="flex items-center justify-between text-[11px]"><label className="flex items-center gap-2 text-slate-500"><input type="checkbox" className="accent-brand"/> Trust this device</label><button type="button" className="font-bold text-brand">Forgot password?</button></div></>:<><label className="label">Security code<input autoFocus className="field mt-2 text-center text-lg tracking-[.35em]" inputMode="numeric" maxLength="6" value={otp} onChange={e=>setOtp(e.target.value.replace(/\D/g,''))} placeholder="246810" required/></label><button type="button" onClick={()=>toast('New demo code: 246810')} className="w-full text-center text-xs font-bold text-brand">Resend security code</button></>}<button className="btn-primary w-full" disabled={loading}>{loading?<LoaderCircle className="animate-spin" size={17}/>:stage==='password'?<LockKeyhole size={16}/>:<ShieldCheck size={16}/>} {stage==='password'?'Continue securely':'Verify & enter console'}</button></form>{stage==='password'&&<div className="mt-5 rounded-xl border border-blue-100 bg-sky p-4 text-xs leading-5 text-slate-600"><strong className="text-navy">Demo Super Admin</strong><br/>superadmin@alliancecargo.in / Admin@123</div>}{stage==='otp'&&<button onClick={()=>setStage('password')} className="mt-5 inline-flex items-center gap-2 text-xs font-bold text-brand"><ArrowLeft size={14}/> Use a different account</button>}<p className="mt-7 flex items-center gap-2 text-[10px] leading-4 text-slate-400"><Shield size={13}/> Protected by role-based access, session timeout and activity monitoring.</p></div></section></main>
}

function Sidebar({route,mobile,setMobile,collapsed,setCollapsed,onLogout}){return <><div onClick={()=>setMobile(false)} className={`fixed inset-0 z-40 bg-navy/45 backdrop-blur-sm lg:hidden ${mobile?'block':'hidden'}`}/><aside className={`fixed inset-y-0 left-0 z-50 flex flex-col bg-navy text-white transition-all duration-300 ${collapsed?'w-[82px]':'w-[274px]'} ${mobile?'translate-x-0':'-translate-x-full'} lg:translate-x-0`}><div className={`flex h-20 items-center border-b border-white/10 ${collapsed?'justify-center px-3':'justify-between px-6'}`}><Logo compact={collapsed} light/><button onClick={()=>setMobile(false)} className="lg:hidden"><X size={19}/></button></div><nav className="flex-1 overflow-y-auto px-3 py-5">{navGroups.map(([group,items])=><div key={group} className="mb-5">{!collapsed&&<p className="mb-2 px-3 text-[8px] font-bold uppercase tracking-[.19em] text-blue-300/50">{group}</p>}<div className="space-y-1">{items.map(([key,label,Icon])=><a key={key} href={`#/${key}`} title={collapsed?label:undefined} onClick={()=>setMobile(false)} className={`flex items-center rounded-xl py-2.5 text-xs font-medium transition ${collapsed?'justify-center px-2':'gap-3 px-3'} ${route===key?'bg-brand text-white shadow-lg shadow-blue-950/20':'text-blue-100/65 hover:bg-white/10 hover:text-white'}`}><Icon size={17}/>{!collapsed&&<span>{label}</span>}{!collapsed&&key==='agents'&&<span className="ml-auto rounded-full bg-gold px-1.5 py-0.5 text-[8px] font-bold text-navy">2</span>}</a>)}</div></div>)}</nav><div className="border-t border-white/10 p-3">{!collapsed&&<div className="mb-2 rounded-xl bg-white/[.07] p-3"><p className="text-[10px] text-blue-200/55">Signed in as</p><strong className="mt-1 block truncate text-xs">Aarav Sharma</strong><span className="mt-1 block text-[9px] text-gold">Super Admin</span></div>}<div className={`flex ${collapsed?'flex-col':'items-center'}`}><button onClick={()=>setCollapsed(!collapsed)} className="grid h-9 flex-1 place-items-center rounded-lg text-blue-100/60 hover:bg-white/10 hover:text-white"><PanelLeftClose size={17} className={collapsed?'rotate-180':''}/></button><button onClick={onLogout} className="grid h-9 flex-1 place-items-center rounded-lg text-blue-100/60 hover:bg-red-500/15 hover:text-red-200"><LogOut size={17}/></button></div></div></aside></>}

function Header({route,mobile,setMobile,collapsed,notifications,globalSearch,setGlobalSearch}){const [bell,setBell]=useState(false),[searchOpen,setSearchOpen]=useState(false);return <header className={`sticky top-0 z-30 flex h-20 items-center justify-between border-b border-slate-200 bg-white/95 px-4 backdrop-blur transition-all sm:px-7 ${collapsed?'lg:ml-[82px]':'lg:ml-[274px]'}`}><div className="flex items-center gap-3"><button onClick={()=>setMobile(true)} className="grid h-10 w-10 place-items-center rounded-lg border border-slate-200 lg:hidden"><Menu size={19}/></button><div><div className="flex items-center gap-2 text-[9px] uppercase tracking-wider text-slate-400"><span>Admin</span><ChevronRight size={11}/><span>{routeNames[route]||'Page'}</span></div><h1 className="font-display mt-1 text-base font-semibold text-navy sm:text-lg">{routeNames[route]||'Not found'}</h1></div></div><div className="flex items-center gap-2 sm:gap-3"><div className="relative hidden md:block"><Search size={16} className="pointer-events-none absolute left-3 top-1/2 -translate-y-1/2 text-slate-400"/><input value={globalSearch} onFocus={()=>setSearchOpen(true)} onChange={e=>{setGlobalSearch(e.target.value);setSearchOpen(true)}} className="field search-field search-field-shortcut w-56 py-2.5 lg:w-72" placeholder="Search system..."/><kbd className="pointer-events-none absolute right-3 top-1/2 -translate-y-1/2 rounded border border-slate-200 bg-slate-50 px-1.5 py-0.5 text-[9px] text-slate-400">⌘ K</kbd>{searchOpen&&globalSearch&&<div className="absolute left-0 right-0 top-12 rounded-xl border border-slate-200 bg-white p-2 shadow-xl"><p className="p-2 text-[10px] text-slate-400">Search modules and records</p>{Object.entries(routeNames).filter(([,v])=>v.toLowerCase().includes(globalSearch.toLowerCase())).slice(0,5).map(([k,v])=><button key={k} onClick={()=>{go(k);setSearchOpen(false);setGlobalSearch('')}} className="flex w-full items-center justify-between rounded-lg p-2 text-left text-xs font-semibold text-navy hover:bg-sky">{v}<ChevronRight size={14}/></button>)}<button onClick={()=>setSearchOpen(false)} className="mt-1 w-full border-t border-slate-100 p-2 text-left text-[10px] text-slate-400">Close results</button></div>}</div><a href={CLIENT_URL} target="_blank" rel="noreferrer" className="hidden rounded-lg border border-slate-200 px-3 py-2.5 text-[10px] font-bold text-navy hover:border-blue-200 hover:text-brand sm:block">Client portal</a><div className="relative"><button onClick={()=>setBell(!bell)} className="relative grid h-10 w-10 place-items-center rounded-lg border border-slate-200 text-slate-500"><Bell size={17}/><span className="absolute right-2 top-2 h-2 w-2 rounded-full bg-gold ring-2 ring-white"/></button>{bell&&<div className="absolute right-0 top-12 w-[min(340px,calc(100vw-2rem))] rounded-xl border border-slate-200 bg-white p-3 shadow-xl"><div className="flex items-center justify-between p-2"><strong className="text-xs text-navy">Notifications</strong><span className="text-[9px] text-brand">Mark all read</span></div>{notifications.slice(0,3).map(n=><div key={n.id} className="border-t border-slate-100 p-3"><p className="text-xs font-semibold text-navy">{n.title}</p><span className="mt-1 block text-[9px] text-slate-400">{n.sent} · {n.channel}</span></div>)}</div>}</div><button className="flex h-10 items-center gap-2 rounded-lg border border-slate-200 px-2"><span className="grid h-7 w-7 place-items-center rounded-full bg-navy text-[9px] font-bold text-white">AS</span><ChevronDown size={13} className="hidden text-slate-400 sm:block"/></button></div></header>}

function PageTitle({eyebrow,title,text,actions}){return <div className="mb-6 flex flex-col justify-between gap-4 sm:flex-row sm:items-end"><div><p className="text-[9px] font-bold uppercase tracking-[.18em] text-brand">{eyebrow}</p><h2 className="font-display mt-2 text-2xl font-semibold tracking-[-.03em] text-navy">{title}</h2>{text&&<p className="mt-2 max-w-2xl text-xs leading-5 text-slate-500">{text}</p>}</div>{actions&&<div className="flex flex-wrap gap-2">{actions}</div>}</div>}

function Badge({value}){const v=String(value||'');let cls='bg-slate-100 text-slate-600';if(/active|paid|verified|delivered|on time|excellent|sent|resolved/i.test(v))cls='bg-green-50 text-green-700';else if(/pending|review|scheduled|booked|credit|medium/i.test(v))cls='bg-amber-50 text-amber-700';else if(/suspended|frozen|cancel|reject|missing|high|delayed|refunded/i.test(v))cls='bg-red-50 text-red-700';else if(/transit|boarding|progress|open/i.test(v))cls='bg-blue-50 text-brand';return <span className={`inline-flex whitespace-nowrap rounded-full px-2.5 py-1 text-[9px] font-bold ${cls}`}>{v}</span>}

function MiniAreaChart(){const vals=[28,36,32,48,44,57,61,56,72,69,86,92];const points=vals.map((v,i)=>`${i*(100/(vals.length-1))},${100-v}`).join(' ');return <svg viewBox="0 0 100 100" preserveAspectRatio="none" className="h-48 w-full" aria-label="Revenue trend"><defs><linearGradient id="area" x1="0" y1="0" x2="0" y2="1"><stop offset="0" stopColor="#0F62FE" stopOpacity=".25"/><stop offset="1" stopColor="#0F62FE" stopOpacity="0"/></linearGradient></defs>{[20,40,60,80].map(y=><line key={y} x1="0" x2="100" y1={y} y2={y} stroke="#e8edf3" strokeWidth=".5"/>)}<polygon points={`0,100 ${points} 100,100`} fill="url(#area)"/><polyline points={points} fill="none" stroke="#0F62FE" strokeWidth="2" vectorEffect="non-scaling-stroke"/><circle cx="100" cy="8" r="2" fill="#0F62FE" vectorEffect="non-scaling-stroke"/></svg>}

function Dashboard({state}){const metrics=[[CircleDollarSign,'Total revenue','₹2.84 Cr','+18.4% vs last month','text-brand bg-blue-50'],[BadgeIndianRupee,"Today's revenue",'₹4.72 L','42 payments received','text-green-600 bg-green-50'],[Box,'Pending bookings','28','8 require action','text-amber-600 bg-amber-50'],[PackageCheck,'Delivered shipments','1,248','96.8% success rate','text-purple-600 bg-purple-50'],[Plane,'Flights today','18','3 currently boarding','text-sky-600 bg-sky'],[Users,'Active agents','126','2 approvals pending','text-brand bg-blue-50'],[UserCog,'Active employees','84','7 on leave today','text-green-600 bg-green-50'],[WalletCards,'Pending payments','₹8.64 L','14 invoices overdue','text-red-600 bg-red-50']];return <div className="fade"><PageTitle eyebrow="Network overview" title="Operations control centre" text="Live executive overview across cargo, revenue, capacity and team operations." actions={[<button key="report" onClick={()=>go('reports')} className="btn-secondary"><FileBarChart size={15}/> View reports</button>,<button key="book" onClick={()=>go('bookings')} className="btn-primary"><Plus size={15}/> New booking</button>]}/><div className="grid gap-3 sm:grid-cols-2 xl:grid-cols-4">{metrics.map(([Icon,l,n,s,c])=><div key={l} className="card p-5"><div className="flex items-start justify-between"><span className={`grid h-10 w-10 place-items-center rounded-xl ${c}`}><Icon size={20}/></span><span className="text-[9px] font-bold text-green-600">LIVE</span></div><strong className="font-display mt-4 block text-[22px] text-navy">{n}</strong><span className="mt-1 block text-[11px] font-semibold text-slate-600">{l}</span><small className="mt-2 block text-[9px] text-slate-400">{s}</small></div>)}</div><div className="mt-5 grid gap-5 xl:grid-cols-[1.35fr_.65fr]"><section className="card p-5 sm:p-6"><div className="flex items-center justify-between"><div><h3 className="font-display text-sm font-semibold text-navy">Revenue performance</h3><p className="mt-1 text-[10px] text-slate-400">Monthly net revenue · FY 2026</p></div><select className="field w-28 py-2"><option>12 months</option><option>6 months</option></select></div><div className="mt-5"><MiniAreaChart/><div className="mt-2 flex justify-between text-[8px] uppercase text-slate-400">{['Aug','Sep','Oct','Nov','Dec','Jan','Feb','Mar','Apr','May','Jun','Jul'].map(x=><span key={x}>{x}</span>)}</div></div></section><section className="card p-5 sm:p-6"><div className="flex items-center justify-between"><h3 className="font-display text-sm font-semibold text-navy">Flight utilization</h3><button onClick={()=>go('flights')} className="text-[10px] font-bold text-brand">View flights</button></div><div className="mt-6 flex justify-center"><div className="relative grid h-40 w-40 place-items-center rounded-full" style={{background:'conic-gradient(#0f62fe 0 73%, #dcecff 73% 100%)'}}><div className="grid h-28 w-28 place-items-center rounded-full bg-white text-center"><div><strong className="font-display text-3xl text-navy">73%</strong><span className="block text-[9px] text-slate-400">Avg. utilized</span></div></div></div></div><div className="mt-6 grid grid-cols-2 gap-3 text-center"><div className="rounded-xl bg-slate-50 p-3"><strong className="text-sm text-navy">342 t</strong><span className="mt-1 block text-[9px] text-slate-400">Cargo today</span></div><div className="rounded-xl bg-slate-50 p-3"><strong className="text-sm text-navy">91 t</strong><span className="mt-1 block text-[9px] text-slate-400">Space available</span></div></div></section></div><div className="mt-5 grid gap-5 xl:grid-cols-[1.2fr_.8fr]"><section className="card overflow-hidden"><div className="flex items-center justify-between border-b border-slate-100 p-5"><div><h3 className="font-display text-sm font-semibold text-navy">Recent bookings</h3><p className="mt-1 text-[10px] text-slate-400">Latest cargo movement</p></div><button onClick={()=>go('bookings')} className="text-[10px] font-bold text-brand">View all</button></div><div className="overflow-x-auto"><table className="w-full min-w-[560px] text-left"><tbody className="divide-y divide-slate-100">{state.bookings.slice(0,4).map(b=><tr key={b.id} className="text-[10px]"><td className="px-5 py-4"><strong className="block text-brand">{b.id}</strong><span className="mt-1 block text-slate-400">{b.agent}</span></td><td className="px-5 py-4 font-bold text-navy">{b.route}</td><td className="px-5 py-4 text-slate-500">{b.weight}</td><td className="px-5 py-4"><Badge value={b.status}/></td></tr>)}</tbody></table></div></section><section className="card p-5"><div className="flex items-center justify-between"><h3 className="font-display text-sm font-semibold text-navy">Recent activity</h3><button onClick={()=>go('audit')} className="text-[10px] font-bold text-brand">Audit log</button></div><div className="mt-4 space-y-4">{state.logs.slice(0,5).map((l,i)=><div key={l.id} className="flex gap-3"><span className={`mt-1 h-2 w-2 shrink-0 rounded-full ${i===0?'bg-brand':'bg-slate-300'}`}/><div><p className="text-[10px] font-semibold leading-4 text-navy">{l.action}</p><span className="text-[9px] text-slate-400">{l.user} · {l.time}</span></div></div>)}</div></section></div></div>}

function DashboardV2({state}) {
  const bookings=state.bookings||[], agents=state.agents||[], flights=state.flights||[], wallets=state.wallets||[]
  const pendingAgents=agents.filter(item=>item.status==='Pending').length
  const pendingDocuments=(state.documents||[]).filter(item=>item.status==='Pending').length
  const openTickets=(state.tickets||[]).filter(item=>!['Resolved','Closed'].includes(item.status)).length
  const walletFloat=wallets.reduce((sum,item)=>sum+Number(item.balance||0),0)
  const metrics=[
    [Box,'Total shipments',bookings.length,`${bookings.filter(item=>item.status==='In transit').length} in transit`,'text-brand bg-blue-50'],
    [Plane,'Active flights',flights.filter(item=>item.status!=='Cancelled').length,`${flights.filter(item=>item.status==='Delayed').length} delayed`,'text-sky-600 bg-sky'],
    [Users,'Active agents',agents.filter(item=>item.status==='Active').length,`${pendingAgents} approvals pending`,'text-purple-600 bg-purple-50'],
    [WalletCards,'Client wallet float',`₹${walletFloat.toLocaleString('en-IN')}`,`${wallets.filter(item=>item.status==='Frozen').length} frozen wallets`,'text-green-600 bg-green-50'],
  ]
  const quickActions=[
    ['bookings','Shipment / AWB','Create, edit, print and monitor bookings',Box,bookings.length,'bg-blue-50 text-brand'],
    ['tracking','Track cargo','Search an AWB and publish milestones',MapPin,'Live','bg-cyan-50 text-cyan-700'],
    ['rateCards','Rate cards','Live sector and weight-slab pricing engine',ListChecks,(state.rateCards||[]).length,'bg-green-50 text-green-700'],
    ['charges','Calculator settings','Default freight and surcharge controls',SlidersHorizontal,'Connected','bg-amber-50 text-amber-700'],
    ['commodities','Commodities','Handling rules and booking surcharges',ClipboardCheck,(state.commodities||[]).length,'bg-purple-50 text-purple-700'],
    ['flights','Flight operations','Schedule, capacity and flight status',Plane,(state.flights||[]).length,'bg-sky text-brand'],
    ['agents','Agent approvals','KYC and commercial account access',UserCheck,pendingAgents,'bg-orange-50 text-orange-700'],
    ['exceptions','NDR / RTO','Resolve delivery and return exceptions',AlertTriangle,(state.exceptions||[]).filter(item=>!['Resolved','Closed'].includes(item.status)).length,'bg-red-50 text-red-700'],
    ['weightAudits','Weight audit','Revenue protection and reweigh variance',Gauge,(state.weightAudits||[]).length,'bg-indigo-50 text-indigo-700'],
    ['wallets','Wallet recharge','Balances, recharge, debit and freeze controls',WalletCards,wallets.length,'bg-emerald-50 text-emerald-700'],
    ['transactions','Transactions','Wallet and customer payment register',CircleDollarSign,(state.walletTransactions||[]).length,'bg-slate-100 text-slate-700'],
  ]
  const actionQueue=[
    [UserCheck,`${pendingAgents} agent approvals`,'Review pending KYC and activate accounts','agents','text-purple-600 bg-purple-50'],
    [FileCheck2,`${pendingDocuments} documents pending`,'Verify customer compliance documents','documents','text-amber-600 bg-amber-50'],
    [Headphones,`${openTickets} support tickets`,'Resolve open operational requests','tickets','text-red-600 bg-red-50'],
  ]
  return <div className="fade">
    <PageTitle eyebrow="Command centre" title="Good afternoon, Aarav" text="Run day-to-day cargo operations, pricing, finance and compliance from one connected dashboard." actions={[<button key="report" onClick={()=>go('reports')} className="btn-secondary"><FileBarChart size={15}/> Reports</button>,<button key="awb" onClick={()=>go('bookings')} className="btn-primary"><Plus size={15}/> Manage shipment</button>]}/>
    <section className="relative mb-5 overflow-hidden rounded-2xl bg-navy p-5 text-white shadow-xl shadow-blue-950/10 sm:p-7">
      <div className="absolute -right-16 -top-24 h-64 w-64 rounded-full border border-white/10"/><div className="absolute -right-2 -top-12 h-44 w-44 rounded-full border border-white/10"/>
      <div className="relative flex flex-col justify-between gap-6 lg:flex-row lg:items-center"><div><div className="flex flex-wrap gap-2"><span className="inline-flex items-center gap-2 rounded-full bg-green-400/10 px-3 py-1.5 text-[9px] font-bold text-green-300"><span className="h-1.5 w-1.5 rounded-full bg-green-400"/> ALL SYSTEMS OPERATIONAL</span><span className="inline-flex items-center gap-2 rounded-full bg-white/10 px-3 py-1.5 text-[9px] font-bold text-blue-100"><Database size={12}/> DATABASE CONNECTED</span></div><h3 className="font-display mt-4 text-xl font-semibold sm:text-2xl">Alliance cargo network is under control.</h3><p className="mt-2 max-w-2xl text-xs leading-6 text-blue-100/70">Wallet-paid bookings, server-side freight calculation and operational audit logging are active across the client network.</p></div><div className="grid shrink-0 grid-cols-2 gap-2 text-center sm:grid-cols-3"><div className="rounded-xl bg-white/[.08] px-4 py-3"><strong className="font-display block text-lg">{bookings.length}</strong><span className="text-[8px] text-blue-200">AWBs</span></div><div className="rounded-xl bg-white/[.08] px-4 py-3"><strong className="font-display block text-lg">{flights.length}</strong><span className="text-[8px] text-blue-200">Flights</span></div><div className="col-span-2 rounded-xl bg-white/[.08] px-4 py-3 sm:col-span-1"><strong className="font-display block text-lg">{agents.length}</strong><span className="text-[8px] text-blue-200">Agents</span></div></div></div>
    </section>
    <section className="grid gap-3 sm:grid-cols-2 xl:grid-cols-4">{metrics.map(([Icon,label,value,meta,color])=><button key={label} onClick={()=>go(label.includes('shipment')?'bookings':label.includes('flight')?'flights':label.includes('agent')?'agents':'wallets')} className="card p-5 text-left transition duration-200 hover:-translate-y-0.5 hover:border-blue-200 hover:shadow-lg"><div className="flex items-start justify-between"><span className={`grid h-10 w-10 place-items-center rounded-xl ${color}`}><Icon size={19}/></span><ArrowRight size={15} className="text-slate-300"/></div><strong className="font-display mt-4 block text-xl text-navy">{value}</strong><span className="mt-1 block text-[10px] font-semibold text-slate-600">{label}</span><small className="mt-2 block text-[9px] text-slate-400">{meta}</small></button>)}</section>
    <div className="mt-5 grid gap-5 xl:grid-cols-[1.45fr_.55fr]"><section className="card p-5 sm:p-6"><div className="flex items-end justify-between gap-3"><div><p className="text-[9px] font-bold uppercase tracking-[.16em] text-brand">Direct controls</p><h3 className="font-display mt-2 text-base font-semibold text-navy">Go straight to a main operation</h3></div><span className="hidden text-[9px] text-slate-400 sm:block">Every card opens a working module</span></div><div className="mt-5 grid gap-3 sm:grid-cols-2 2xl:grid-cols-4">{quickActions.map(([route,label,text,badgeIcon,badge,tone])=>{const Icon=badgeIcon;return <button key={route} onClick={()=>go(route)} className="group rounded-xl border border-slate-100 p-4 text-left transition hover:border-blue-200 hover:bg-sky/60 hover:shadow-md"><div className="flex items-start justify-between"><span className={`grid h-10 w-10 place-items-center rounded-xl ${tone}`}><Icon size={18}/></span><span className="rounded-full bg-slate-100 px-2 py-1 text-[8px] font-bold text-slate-500">{badge}</span></div><strong className="mt-4 block text-[11px] text-navy group-hover:text-brand">{label}</strong><p className="mt-1 text-[9px] leading-4 text-slate-400">{text}</p><span className="mt-3 inline-flex items-center gap-1 text-[9px] font-bold text-brand">Open module <ArrowRight size={12}/></span></button>})}</div></section><aside className="card overflow-hidden"><div className="border-b border-slate-100 p-5"><div className="flex items-center justify-between"><h3 className="font-display text-sm font-semibold text-navy">Action queue</h3><span className="rounded-full bg-red-50 px-2 py-1 text-[8px] font-bold text-red-600">{pendingAgents+pendingDocuments+openTickets} OPEN</span></div><p className="mt-1 text-[9px] text-slate-400">Items that need administrator attention</p></div><div className="divide-y divide-slate-100">{actionQueue.map(([Icon,title,text,route,tone])=><button key={route} onClick={()=>go(route)} className="flex w-full items-center gap-3 p-4 text-left transition hover:bg-slate-50"><span className={`grid h-9 w-9 shrink-0 place-items-center rounded-xl ${tone}`}><Icon size={16}/></span><span className="min-w-0 flex-1"><strong className="block text-[10px] text-navy">{title}</strong><small className="mt-1 block truncate text-[8px] text-slate-400">{text}</small></span><ChevronRight size={14} className="text-slate-300"/></button>)}</div></aside></div>
    <div className="mt-5 grid gap-5 xl:grid-cols-[1.2fr_.8fr]"><section className="card overflow-hidden"><div className="flex items-center justify-between border-b border-slate-100 p-5"><div><h3 className="font-display text-sm font-semibold text-navy">Latest shipments</h3><p className="mt-1 text-[9px] text-slate-400">Recently created air waybills</p></div><button onClick={()=>go('bookings')} className="text-[9px] font-bold text-brand">Manage all</button></div><div className="overflow-x-auto"><table className="w-full min-w-[560px] text-left"><tbody className="divide-y divide-slate-100">{bookings.slice(0,4).map(item=><tr key={item.id} className="text-[10px]"><td className="px-5 py-4"><button onClick={()=>go('bookings')} className="font-bold text-brand">{item.id}</button><span className="mt-1 block text-[9px] text-slate-400">{item.agent}</span></td><td className="px-5 py-4 font-semibold text-navy">{item.route}</td><td className="px-5 py-4 text-slate-500">{item.commodity}</td><td className="px-5 py-4"><Badge value={item.status}/></td></tr>)}</tbody></table></div></section><section className="card p-5"><div className="flex items-center justify-between"><h3 className="font-display text-sm font-semibold text-navy">Recent activity</h3><button onClick={()=>go('audit')} className="text-[9px] font-bold text-brand">Full audit log</button></div><div className="mt-4 space-y-4">{(state.logs||[]).slice(0,5).map((item,index)=><div key={item.id} className="flex gap-3"><span className={`mt-1 h-2 w-2 shrink-0 rounded-full ${index===0?'bg-brand':'bg-slate-300'}`}/><div><p className="text-[10px] font-semibold leading-4 text-navy">{item.action}</p><span className="text-[8px] text-slate-400">{item.user} · {item.time}</span></div></div>)}</div></section></div>
  </div>
}

const weekdays=['Mon','Tue','Wed','Thu','Fri','Sat','Sun']
const readableDate=value=>{if(!value)return'';const parsed=new Date(`${value}T00:00:00`);return Number.isNaN(parsed.getTime())?value:parsed.toLocaleDateString('en-GB',{day:'2-digit',month:'short',year:'numeric'})}
const normalizeFlight=form=>{
  const capacityKg=Math.max(0,Number(form.capacityKg||0)),availableKg=Math.min(capacityKg,Math.max(0,Number(form.availableKg||0)))
  const utilization=capacityKg?`${Math.round((1-(availableKg/capacityKg))*100)}%`:'0%'
  return {...form,capacityKg,availableKg,origin:String(form.origin||'').toUpperCase(),destination:String(form.destination||'').toUpperCase(),route:`${String(form.origin||'').toUpperCase()} → ${String(form.destination||'').toUpperCase()}`,departure:`${readableDate(form.departureDate)}, ${form.departureTime}`,capacity:`${capacityKg.toLocaleString('en-IN')} kg`,available:`${availableKg.toLocaleString('en-IN')} kg`,utilization}
}
const normalizeFare=form=>({...form,origin:String(form.origin||'').toUpperCase(),destination:String(form.destination||'').toUpperCase(),route:`${String(form.origin||'').toUpperCase()} → ${String(form.destination||'').toUpperCase()}`,slab:`${form.weightFrom||0}–${form.weightTo||'∞'} kg`,base:`₹${Number(form.baseRatePerKg||0).toLocaleString('en-IN')}/kg`,fuel:`${form.fuelSurcharge||0}%`,gst:`${form.gst||0}%`,seasonal:form.seasonal||'No',customer:form.customer||'Standard'})
const normalizeRateCard=form=>{const origin=String(form.origin||'').toUpperCase(),destination=String(form.destination||'').toUpperCase(),minWeight=Math.max(0,Number(form.minWeight||0)),maxWeight=Math.max(minWeight,Number(form.maxWeight||0));return {...form,origin,destination,minWeight,maxWeight,ratePerKg:Number(form.ratePerKg||0),minimumFreight:Number(form.minimumFreight||0),volumetricDivisor:Number(form.volumetricDivisor||6000),fuelSurchargePercent:Number(form.fuelSurchargePercent||0),sectorSurcharge:Number(form.sectorSurcharge||0),handlingCharge:Number(form.handlingCharge||0),xrayRatePerKg:Number(form.xrayRatePerKg||0),sector:`${origin} → ${destination}`,weightSlab:`${minWeight}–${maxWeight} kg`,rateDisplay:`₹${Number(form.ratePerKg||0).toLocaleString('en-IN')}/kg`,minimumDisplay:`₹${Number(form.minimumFreight||0).toLocaleString('en-IN')}`}}
const normalizeWeightAudit=form=>{const pieces=Math.max(1,Number(form.pieces||1)),declaredWeight=Math.max(0,Number(form.declaredWeight||0)),actualWeight=Math.max(0,Number(form.actualWeight||0)),divisor=Math.max(1,Number(form.volumetricDivisor||6000)),volumetricWeight=(Number(form.length||0)*Number(form.width||0)*Number(form.height||0)*pieces)/divisor,chargeableWeight=Math.ceil(Math.max(actualWeight,volumetricWeight)),variance=Number((chargeableWeight-declaredWeight).toFixed(2)),adjustmentAmount=Number((Math.max(0,variance)*Number(form.currentRatePerKg||0)).toFixed(2));return {...form,pieces,declaredWeight,actualWeight,volumetricDivisor:divisor,volumetricWeight:Number(volumetricWeight.toFixed(2)),chargeableWeight,variance,adjustmentAmount}}

