function EnhancedEntityForm({fields,value,onSubmit,onCancel}){
  const initial=Object.fromEntries(fields.filter(([, ,type])=>type!=='section').map(([key,,type,options])=>[key,value?.[key]??(type==='select'?options[0]:type==='days'?[]:'')]))
  const [form,setForm]=useState(initial),[error,setError]=useState('')
  const submit=event=>{event.preventDefault();const missingDays=fields.find(([key,,type,,optional])=>type==='days'&&!optional&&!(form[key]||[]).length);if(missingDays){setError(`Select at least one ${missingDays[1].toLowerCase()}.`);return}setError('');onSubmit(form)}
  const toggleDay=(key,day)=>setForm(current=>({...current,[key]:(current[key]||[]).includes(day)?current[key].filter(item=>item!==day):[...(current[key]||[]),day]}))
  return <form onSubmit={submit}><div className="grid gap-4 sm:grid-cols-2">{fields.map(([key,label,type,options,optional])=>{
    if(type==='section')return <div key={key} className="form-section sm:col-span-2"><span>{label}</span></div>
    const wide=type==='textarea'||type==='days'||key==='email'||key==='route'
    if(type==='days')return <fieldset key={key} className={`label ${wide?'sm:col-span-2':''}`}><legend>{label} {!optional&&'*'}</legend><div className="mt-2 grid grid-cols-4 gap-2 sm:grid-cols-7">{options.map(day=><button type="button" key={day} aria-pressed={(form[key]||[]).includes(day)} onClick={()=>toggleDay(key,day)} className={`day-option ${(form[key]||[]).includes(day)?'is-selected':''}`}>{day}</button>)}</div></fieldset>
    return <label key={key} className={`label ${wide?'sm:col-span-2':''}`}>{label} {!optional&&'*'}{type==='select'?<select required={!optional} className="field mt-2" value={form[key]||''} onChange={event=>setForm({...form,[key]:event.target.value})}>{options.map(option=><option key={option}>{option}</option>)}</select>:type==='textarea'?<textarea required={!optional} rows="3" className="field mt-2 resize-y" value={form[key]||''} onChange={event=>setForm({...form,[key]:event.target.value})}/>:<input required={!optional} min={type==='number'?'0':undefined} step={type==='number'?'0.01':undefined} className="field mt-2" type={type} value={form[key]??''} onChange={event=>setForm({...form,[key]:event.target.value})}/>}</label>
  })}</div>{error&&<p role="alert" className="mt-4 rounded-xl bg-red-50 p-3 text-[10px] font-semibold text-red-700">{error}</p>}<div className="mt-6 flex justify-end gap-2"><button type="button" onClick={onCancel} className="btn-secondary">Cancel</button><button className="btn-primary"><Check size={15}/> Save record</button></div></form>
}

