  charges:{eyebrow:'Commercial configuration',title:'Freight charge controls',text:'Connected to the client New Shipment calculator. Edit the active profile, save it, and the next client calculation uses the updated values. Enter 0 to disable a charge.',singular:'Charge profile',prefix:'CHG',columns:[['name','Profile'],['baseRatePerKg','Base ₹/kg'],['minimumChargeableWeight','Minimum kg'],['xrayRatePerKg','X-ray ₹/kg'],['commoditySurcharge','Commodity'],['originStationCharge','Origin'],['status','Connection']],fields:[['name','Profile name','text'],['baseRatePerKg','Base freight rate ₹/kg','number'],['minimumChargeableWeight','Minimum chargeable weight kg','number'],['volumetricDivisor','Volumetric divisor','number'],['sectorSurcharge','Sector surcharge ₹','number'],['flightSurcharge','Flight surcharge ₹','number'],['commoditySurcharge','Commodity surcharge ₹','number'],['originStationCharge','Origin station charge ₹','number'],['destinationStationCharge','Destination station charge ₹','number'],['xrayRatePerKg','X-ray rate ₹/kg','number'],['handleWithCareCharge','Handle with care ₹','number'],['priorityHandlingCharge','Priority handling ₹','number'],['temperatureControlCharge','Temperature control ₹','number'],['status','Client calculator connection','select',['Active','Inactive']]]},
